SELECT company_name
FROM portfolio_companies
WHERE ipo_status = 1;

SELECT AVG(CAST(REPLACE(ir.post_money_valuation, ',', '') AS REAL)) AS average_post_money_valuation
FROM investment_rounds ir
WHERE ir.round_type = 'Series A';

SELECT company_name
FROM portfolio_companies
ORDER BY company_name;

SELECT company_id, COUNT(round_id) AS total_rounds
FROM investment_rounds
GROUP BY company_id;
